        "html": "<!DOCTYPE html>\n<html>\n<head>\n  <meta charset=\"UTF-8\">\n  <style>\n    @import url('https://cdn.jsdelivr.net/gh/orioncactus/pretendard/dist/web/static/pretendard.css');\n    * { margin: 0; padding: 0; box-sizing: border-box; }\n    body { font-family: 'Pretendard', sans-serif; margin: 0; padding: 0; background-color: #F4F7F9; }\n    .canvas { width: 1080px; height: 1350px; position: relative; overflow: hidden; background-color: #F4F7F9; }\n    .guide-line { position: absolute; left: 80px; top: 0; bottom: 0; width: 1px; background-color: #5C8CC0; opacity: 0.4; z-index: 0; }\n    .top-dots { position: absolute; top: 40px; right: 50px; display: flex; gap: 12px; z-index: 10; }\n    .dot { width: 24px; height: 24px; border: 2px solid #5C8CC0; border-radius: 50%; box-sizing: border-box; }\n    .content-area { position: absolute; top: 50%; left: 50%; transform: translate(-50%, -50%); width: 80%; text-align: center; z-index: 10; }\n    .subtitle { font-size: 24px; font-weight: 700; color: #99AABB; letter-spacing: 4px; margin-bottom: 30px; text-transform: uppercase; }\n    .main-title { font-size: 130px; font-weight: 800; line-height: 1.1; color: #1F2D3D; margin-bottom: 20px; white-space: nowrap; }\n    .title-highlight-box { display: inline-block; background-color: #5C8CC0; color: white; padding: 10px 40px; font-size: 130px; font-weight: 800; line-height: 1.1; position: relative; margin-top: 10px; }\n    .cursor-icon { position: absolute; bottom: -60px; right: -40px; width: 80px; height: 80px; filter: drop-shadow(0 4px 6px rgba(0,0,0,0.2)); }\n    .description { margin-top: 80px; font-size: 32px; color: #666666; line-height: 1.5; font-weight: 500; }\n    .footer-handle { position: absolute; bottom: 80px; left: 0; width: 100%; text-align: center; font-size: 32px; font-weight: 700; color: #1F2D3D; }\n    .arrow-icon { position: absolute; bottom: 80px; right: 60px; width: 50px; height: 50px; fill: #5C8CC0; opacity: 0.8; }\n  </style>\n</head>\n<body>\n  <div class=\"canvas\">\n    <!-- Decorative Elements -->\n    <div class=\"guide-line\"></div>\n    <div class=\"top-dots\">\n      <div class=\"dot\"></div>\n      <div class=\"dot\"></div>\n      <div class=\"dot\"></div>\n    </div>\n\n    <!-- Main Content -->\n    <div class=\"content-area\">\n      <div class=\"subtitle\">Cardnews Layout Template</div>\n      <div class=\"main-title\">CARD NEWS</div>\n      <div class=\"main-title\">LAYOUT</div>\n      <div class=\"title-highlight-box\">\n        COLLECTION\n        <!-- Cursor Icon SVG -->\n        <svg class=\"cursor-icon\" viewBox=\"0 0 24 24\" fill=\"#1F2D3D\" xmlns=\"http://www.w3.org/2000/svg\">\n          <path d=\"M5.5 3.21V20.8c0 .45.54.67.85.35l4.86-4.86a.5.5 0 0 1 .35-.15h6.87a.45.45 0 0 0 .32-.77L6.18 2.96a.45.45 0 0 0-.68.25z\"/>\n        </svg>\n      </div>\n      <div class=\"description\">\n        Strategies for attractive visual composition<br>\n        Shall we find out right now?\n      </div>\n    </div>\n\n    <div class=\"footer-handle\">@reallygreatsite</div>\n    \n    <!-- Next Arrow -->\n    <svg class=\"arrow-icon\" viewBox=\"0 0 24 24\" xmlns=\"http://www.w3.org/2000/svg\">\n      <path d=\"M8.59 16.59L13.17 12 8.59 7.41 10 6l6 6-6 6-1.41-1.41z\"/>\n      <path d=\"M12.59 16.59L17.17 12 12.59 7.41 14 6l6 6-6 6-1.41-1.41z\" opacity=\"0.5\"/>\n    </svg>\n  </div>\n</body>\n</html>"
