        "html": "<!DOCTYPE html>\n<html>\n<head>\n  <meta charset=\"UTF-8\">\n  <style>\n    @import url('https://cdn.jsdelivr.net/gh/orioncactus/pretendard/dist/web/static/pretendard.css');\n    * { margin: 0; padding: 0; box-sizing: border-box; }\n    body { font-family: 'Pretendard', sans-serif; margin: 0; padding: 0; background-color: #F4F7F9; }\n    .canvas { width: 1080px; height: 1350px; position: relative; overflow: hidden; background-color: #F4F7F9; }\n    .guide-line { position: absolute; left: 80px; top: 0; bottom: 0; width: 1px; background-color: #5C8CC0; opacity: 0.4; z-index: 0; }\n    .top-dots { position: absolute; top: 40px; right: 50px; display: flex; gap: 12px; z-index: 10; }\n    .dot { width: 24px; height: 24px; border: 2px solid #5C8CC0; border-radius: 50%; box-sizing: border-box; }\n    .header { position: absolute; top: 200px; width: 100%; text-align: center; z-index: 10; }\n    .header-text { font-size: 80px; font-weight: 700; line-height: 1.2; color: #1F2D3D; }\n    .header-highlight { color: #5C8CC0; }\n    .list-container { position: absolute; top: 500px; left: 50%; transform: translateX(-50%); width: 800px; display: flex; flex-direction: column; gap: 40px; z-index: 10; }\n    .list-item { width: 100%; height: 140px; background-color: #E3EAF2; border-radius: 16px; display: flex; align-items: center; padding: 0 50px; }\n    .item-number { font-size: 40px; font-weight: 400; color: #5C8CC0; width: 80px; }\n    .item-divider { width: 2px; height: 60px; background-color: #BBCDDF; margin: 0 40px; }\n    .item-text { font-size: 40px; font-weight: 600; color: #1F2D3D; }\n  </style>\n</head>\n<body>\n  <div class=\"canvas\">\n    <!-- Decorative Elements -->\n    <div class=\"guide-line\"></div>\n    <div class=\"top-dots\">\n      <div class=\"dot\"></div>\n      <div class=\"dot\"></div>\n      <div class=\"dot\"></div>\n    </div>\n\n    <!-- Header -->\n    <div class=\"header\">\n      <div class=\"header-text\">\n        <span class=\"header-highlight\">Easy-to-View</span><br>\n        Table of Contents\n      </div>\n    </div>\n\n    <!-- List Items -->\n    <div class=\"list-container\">\n      <div class=\"list-item\">\n        <div class=\"item-number\">01</div>\n        <div class=\"item-divider\"></div>\n        <div class=\"item-text\">Image Centered Layout</div>\n      </div>\n      <div class=\"list-item\">\n        <div class=\"item-number\">02</div>\n        <div class=\"item-divider\"></div>\n        <div class=\"item-text\">Split Section Layout</div>\n      </div>\n      <div class=\"list-item\">\n        <div class=\"item-number\">03</div>\n        <div class=\"item-divider\"></div>\n        <div class=\"item-text\">Graph & Chart Layout</div>\n      </div>\n      <div class=\"list-item\">\n        <div class=\"item-number\">04</div>\n        <div class=\"item-divider\"></div>\n        <div class=\"item-text\">Full Image Layout</div>\n      </div>\n    </div>\n  </div>\n</body>\n</html>"
