        "html": "<!DOCTYPE html>\n<html>\n<head>\n  <meta charset=\"UTF-8\">\n  <style>\n    @import url('https://cdn.jsdelivr.net/gh/orioncactus/pretendard/dist/web/static/pretendard.css');\n    * { margin: 0; padding: 0; box-sizing: border-box; }\n    body { font-family: 'Pretendard', sans-serif; margin: 0; padding: 0; background-color: #F4F7F9; }\n    .canvas { width: 1080px; height: 1350px; position: relative; overflow: hidden; background-color: #F4F7F9; }\n    .guide-line { position: absolute; left: 80px; top: 0; bottom: 0; width: 1px; background-color: #5C8CC0; opacity: 0.4; z-index: 0; }\n    .top-dots { position: absolute; top: 40px; right: 50px; display: flex; gap: 12px; z-index: 10; }\n    .dot { width: 24px; height: 24px; border: 2px solid #5C8CC0; border-radius: 50%; box-sizing: border-box; }\n    .header { position: absolute; top: 200px; width: 100%; text-align: center; z-index: 10; }\n    .header-text { font-size: 80px; font-weight: 700; color: #1F2D3D; letter-spacing: -2px; }\n    .header-highlight { color: #5C8CC0; margin-right: 10px; }\n    .image-container { position: absolute; top: 400px; left: 50%; transform: translateX(-50%); width: 800px; height: 450px; border-radius: 24px; overflow: hidden; background-color: #1F2D3D; box-shadow: 0 20px 40px rgba(31, 45, 61, 0.15); z-index: 10; }\n    .description-box { position: absolute; top: 920px; width: 100%; text-align: center; padding: 0 100px; z-index: 10; }\n    .desc-text { font-size: 36px; line-height: 1.6; color: #333333; font-weight: 500; word-break: keep-all; }\n  </style>\n</head>\n<body>\n  <div class=\"canvas\">\n    <!-- Decorative Elements -->\n    <div class=\"guide-line\"></div>\n    <div class=\"top-dots\">\n      <div class=\"dot\"></div>\n      <div class=\"dot\"></div>\n      <div class=\"dot\"></div>\n    </div>\n\n    <!-- Header -->\n    <div class=\"header\">\n      <div class=\"header-text\">\n        <span class=\"header-highlight\">Image Focused</span>Layout\n      </div>\n    </div>\n\n    <!-- Main Image Slot -->\n    <div class=\"image-container\">\n      <div class=\"image-slot\" data-slot-type=\"main\" data-slot-label=\"Key Visual Image\"\n           style=\"position: relative; width: 100%; height: 100%; background-color: #e2e8f0; background-image: url('https://kdbgplpcoiwdnnbswlfe.supabase.co/storage/v1/object/public/placeholder/image-placeholder.svg'); background-size: cover; background-position: center;\">\n      </div>\n    </div>\n\n    <!-- Description -->\n    <div class=\"description-box\">\n      <div class=\"desc-text\">\n        Place an image centrally and use text supplementally\n        to leave a strong visual impression.\n        This is especially effective when using images with strong messages.\n      </div>\n    </div>\n  </div>\n</body>\n</html>"
