        "pageType": "content",
        "html": "<!DOCTYPE html>\n<html>\n<head>\n  <meta charset=\"UTF-8\">\n  <style>\n    @import url('https://cdn.jsdelivr.net/gh/orioncactus/pretendard/dist/web/static/pretendard.css');\n    * { margin: 0; padding: 0; box-sizing: border-box; }\n    body { font-family: 'Pretendard', sans-serif; margin: 0; padding: 0; background-color: #F4F7F9; }\n    .canvas { width: 1080px; height: 1350px; position: relative; overflow: hidden; background-color: #F4F7F9; }\n    .guide-line { position: absolute; left: 80px; top: 0; bottom: 0; width: 1px; background-color: #5C8CC0; opacity: 0.4; z-index: 0; }\n    .top-dots { position: absolute; top: 40px; right: 50px; display: flex; gap: 12px; z-index: 10; }\n    .dot { width: 24px; height: 24px; border: 2px solid #5C8CC0; border-radius: 50%; box-sizing: border-box; }\n    .header { position: absolute; top: 200px; width: 100%; text-align: center; z-index: 10; }\n    .header-text { font-size: 80px; font-weight: 700; color: #1F2D3D; letter-spacing: -2px; }\n    .header-highlight { color: #5C8CC0; margin-right: 10px; }\n    .cards-container { position: absolute; top: 400px; left: 50%; transform: translateX(-50%); width: 800px; display: flex; flex-direction: column; gap: 40px; z-index: 10; }\n    .card { width: 100%; height: 360px; background-color: #FFFFFF; border: 3px solid #6da0d3; border-radius: 20px; display: flex; align-items: center; padding: 0 60px; box-shadow: 0 10px 20px rgba(92, 140, 192, 0.1); }\n    .icon-area { width: 120px; height: 120px; flex-shrink: 0; display: flex; justify-content: center; align-items: center; }\n    .card-divider { width: 1px; height: 140px; background-color: #6da0d3; margin: 0 50px; }\n    .card-content { font-size: 34px; line-height: 1.5; color: #1F2D3D; font-weight: 500; word-break: keep-all; }\n  </style>\n</head>\n<body>\n  <div class=\"canvas\">\n    <!-- Decorative Elements -->\n    <div class=\"guide-line\"></div>\n    <div class=\"top-dots\">\n      <div class=\"dot\"></div>\n      <div class=\"dot\"></div>\n      <div class=\"dot\"></div>\n    </div>\n\n    <!-- Header -->\n    <div class=\"header\">\n      <div class=\"header-text\">\n        <span class=\"header-highlight\">Split Section</span>Layout\n      </div>\n    </div>\n\n    <!-- Cards -->\n    <div class=\"cards-container\">\n      <!-- Card 1 -->\n      <div class=\"card\">\n        <div class=\"icon-area\">\n           <div class=\"image-slot\" data-slot-type=\"icon\" data-slot-label=\"Icon 1\"\n             style=\"position: relative; width: 100px; height: 100px; background-color: #eff6ff; background-image: url('https://kdbgplpcoiwdnnbswlfe.supabase.co/storage/v1/object/public/placeholder/image-placeholder.svg'); background-size: cover; background-position: center; border-radius: 50%;\">\n          </div>\n        </div>\n        <div class=\"card-divider\"></div>\n        <div class=\"card-content\">\n          Divide the card into multiple sections to provide separate pieces of information.\n        </div>\n      </div>\n      \n      <!-- Card 2 -->\n      <div class=\"card\">\n        <div class=\"icon-area\">\n           <div class=\"image-slot\" data-slot-type=\"icon\" data-slot-label=\"Icon 2\"\n             style=\"position: relative; width: 100px; height: 100px; background-color: #eff6ff; background-image: url('https://kdbgplpcoiwdnnbswlfe.supabase.co/storage/v1/object/public/placeholder/image-placeholder.svg'); background-size: cover; background-position: center; border-radius: 50%;\">\n          </div>\n        </div>\n        <div class=\"card-divider\"></div>\n        <div class=\"card-content\">\n          Clear visual distinction helps readers absorb information easily.\n        </div>\n      </div>\n    </div>\n  </div>\n</body>\n</html>"
