function normalizeStyleGuide(styleGuide: ImportedStyleGuide): HtmlDesignPreset["styleGuide"] {
  const fontFamily = String(styleGuide.fontFamily || "Inter").trim() || "Inter";
  return {
    fontFamily,
    headingFontFamily: fontFamily,
    bodyFontFamily: fontFamily,
    primaryColor: String(styleGuide.primaryColor || "#111827").trim() || "#111827",
    secondaryColor: String(styleGuide.secondaryColor || "#E5E7EB").trim() || "#E5E7EB",
    accentColor: String(styleGuide.accentColor || "#2563EB").trim() || "#2563EB",
    backgroundColor: String(styleGuide.backgroundColor || "#FFFFFF").trim() || "#FFFFFF",
    designPatterns: Array.isArray(styleGuide.designPatterns) ? styleGuide.designPatterns.filter(Boolean) : [],
  };
}

function toTemplateName(presetName: string, pageType: HtmlPresetPageType | null | undefined, index: number) {
  const suffix = pageType ? pageType[0].toUpperCase() + pageType.slice(1) : "Page";
  return `${presetName} ${suffix} ${index + 1}`;
}

